<?php
namespace ccxt;

// ----------------------------------------------------------------------------

// PLEASE DO NOT EDIT THIS FILE, IT IS GENERATED AND WILL BE OVERWRITTEN:
// https://github.com/ccxt/ccxt/blob/master/CONTRIBUTING.md#how-to-contribute-code

// -----------------------------------------------------------------------------


function test_clone() {
    $exchange = new \ccxt\async\Exchange(array(
        'id' => 'sampleexchange',
    ));
    $obj1 = array(
        'a' => 1,
        'b' => [1, 2, 3],
        'c' => [array(
    'test1' => 1,
    'test2' => 1,
)],
        'd' => null,
        'e' => 'not_undefined',
        'sub' => array(
            'a' => 1,
            'b' => [1, 2],
            'c' => [array(
    'test1' => 1,
    'test2' => 2,
)],
            'd' => null,
            'e' => 'not_undefined',
            'other1' => 'x',
        ),
        'other1' => 'x',
    );
    $obj2 = array(
        'a' => 2,
        'b' => [3, 4],
        'c' => [array(
    'test1' => 2,
    'test3' => 3,
)],
        'd' => 'not_undefined',
        'e' => null,
        'sub' => array(
            'a' => 2,
            'b' => [3, 4],
            'c' => [array(
    'test1' => 2,
    'test3' => 3,
)],
            'd' => 'not_undefined',
            'e' => null,
            'other2' => 'y',
        ),
        'other2' => 'y',
    );
    // deepExtend
    $deep_extended = $exchange->deep_extend($obj1, $obj2);
    $compare_to = array(
        'a' => 2,
        'b' => [3, 4],
        'c' => [array(
    'test1' => 2,
    'test3' => 3,
)],
        'd' => 'not_undefined',
        'e' => null,
        'sub' => array(
            'a' => 2,
            'b' => [3, 4],
            'c' => [array(
    'test1' => 2,
    'test3' => 3,
)],
            'd' => 'not_undefined',
            'e' => null,
            'other1' => 'x',
            'other2' => 'y',
        ),
        'other1' => 'x',
        'other2' => 'y',
    );
    // todo: results are different across langs.
    // to avoid delay to this PR, I comment out this now, but will return to this after this PR merged
    assert_deep_equal($exchange, null, 'testDeepExtend', $deep_extended, $compare_to);
    // -------------------------------------------------------------------------
    // test immutability / no cross-mutation between clone and original
    // -------------------------------------------------------------------------
    // --- test A: shallow-object clone – mutating the clone must not affect original ---
    $simple_orig = array(
        'x' => 1,
        'y' => 'hello',
        'z' => null,
    );
    $simple_clone = $exchange->clone($simple_orig);
    assert($simple_clone['x'] === 1, 'clone A: x');
    assert($simple_clone['y'] === 'hello', 'clone A: y');
    assert($simple_clone['z'] === null, 'clone A: z');
    $simple_clone['x'] = 999;
    $simple_clone['y'] = 'mutated';
    assert($simple_orig['x'] === 1, 'clone A: mutating clone must not change original x');
    assert($simple_orig['y'] === 'hello', 'clone A: mutating clone must not change original y');
    // mutating the original must not affect an already-taken clone
    $simple_orig['x'] = 42;
    assert($simple_clone['x'] === 999, 'clone A: mutating original must not change clone x');
    // -------------------------------------------------------------------------
    // --- test B: nested object – verify clone is a shallow copy (top-level keys independent) ---
    $nested_orig = array(
        'top' => 'original',
        'arr' => [10, 20, 30],
        'sub' => array(
            'inner' => 'original',
        ),
    );
    $nested_clone = $exchange->clone($nested_orig);
    // top-level scalar: independent
    $nested_clone['top'] = 'cloned';
    assert($nested_orig['top'] === 'original', 'clone B: top-level scalar independence – original unchanged');
    assert($nested_clone['top'] === 'cloned', 'clone B: top-level scalar independence – clone updated');
    $nested_orig['top'] = 'changed_orig';
    assert($nested_clone['top'] === 'cloned', 'clone B: changing original top must not affect clone');
    // -------------------------------------------------------------------------
    // --- test C: cloning an empty object ---
    $empty_clone = $exchange->clone(array());
    assert(count(is_array($empty_clone) ? array_keys($empty_clone) : array()) === 0, 'clone C: cloning empty object gives empty object');
    $empty_clone['newKey'] = 'injected';
    // confirm the operation didn't throw and the value was set
    assert($empty_clone['newKey'] === 'injected', 'clone C: can add key to clone of empty object');
    // -------------------------------------------------------------------------
    // --- test D: cloning an object with undefined values preserves those keys ---
    $with_undef = array(
        'present' => 'yes',
        'absent' => null,
    );
    $undef_clone = $exchange->clone($with_undef);
    assert(is_array($undef_clone) && array_key_exists('present', $undef_clone), 'clone D: present key must exist in clone');
    assert($undef_clone['present'] === 'yes', 'clone D: present value preserved');
    assert(is_array($undef_clone) && array_key_exists('absent', $undef_clone), 'clone D: undefined key must still exist in clone');
    assert($undef_clone['absent'] === null, 'clone D: undefined value preserved');
    // mutate clone – original untouched
    $undef_clone['present'] = 'no';
    assert($with_undef['present'] === 'yes', 'clone D: mutating clone must not change original');
    // -------------------------------------------------------------------------
    // --- test E: multi-step: clone → mutate clone → re-clone original → compare ---
    $master_orig = array(
        'a' => 1,
        'b' => 2,
        'c' => 3,
    );
    $clone1 = $exchange->clone($master_orig);
    $clone1['a'] = 100;
    $clone1['d'] = 999; // add extra key
    // original still pristine
    assert($master_orig['a'] === 1, 'clone E: original a untouched after clone1 mutation');
    assert(!(is_array($master_orig) && array_key_exists('d', $master_orig)), 'clone E: extra key must not appear in original');
    // second independent clone from the still-pristine original
    $clone2 = $exchange->clone($master_orig);
    assert($clone2['a'] === 1, 'clone E: clone2 starts from pristine original');
    assert(!(is_array($clone2) && array_key_exists('d', $clone2)), 'clone E: clone2 must not inherit clone1 extra key');
    // mutate clone2 differently
    $clone2['b'] = 200;
    assert($clone1['b'] === 2, 'clone E: clone1.b unaffected by clone2 mutation');
    assert($master_orig['b'] === 2, 'clone E: original.b unaffected by clone2 mutation');
}
